try {
  const wd = sim.worldData
  if (!wd.__sw) wd.__sw = { gx: 0, gy: 0, lid: 0.45, smile: 0.35, pulse: 0, blush: 0.2, sleep: 0, glow: 0, holdT: 0, mn: 0, blinkT: 0, snoreT: 0 }
  const S = wd.__sw
  const pdt = Math.min(dt, 0.05)

  // ── the moon's orbit clock, now shared with the shader (was time*0.35) ──
  if (typeof S.ma !== 'number') S.ma = 0
  S.ma += pdt * 0.35
  const mcx = Math.cos(S.ma) * 0.72
  const mcy = Math.sin(S.ma) * 0.62 * 0.72
  const mR = 0.075

  // ── the planet's face (unchanged behaviour) ──
  const mx = ((wd.mouse_x ?? 256) - 256) / 256
  const my = ((wd.mouse_y ?? 256) - 256) / 256
  const dc = Math.hypot(mx, my)
  let tgx = mx * 0.8, tgy = my * 0.8
  let tSmile = 0.35, tLid = 0.45
  if (dc < 0.45) { tgx = -mx * 0.7; tgy = -my * 0.5; tSmile = 0.8; tLid = 0.6 }
  S.gx += (Math.max(-1, Math.min(1, tgx)) - S.gx) * Math.min(1, pdt * 6)
  S.gy += (Math.max(-1, Math.min(1, tgy)) - S.gy) * Math.min(1, pdt * 6)

  const mn = wd.mouse_down_n || 0
  if (mn > S.mn) {
    S.mn = mn
    S.blinkT = 0.7
    S.pulse = 1
    S.blush = Math.min(1, S.blush + 0.3)
    S.glow = 1
    wd.__play_sound = [
      { frequency: 220, duration: 0.12, volume: 0.3, type: 'sine' },
      { frequency: 165, duration: 0.22, volume: 0.25, type: 'sine' },
    ]
  }
  if (wd.mouse_down) { S.holdT += pdt } else { S.holdT = 0 }
  const sleeping = S.holdT > 0.7
  S.sleep += ((sleeping ? 1 : 0) - S.sleep) * Math.min(1, pdt * 4)
  if (sleeping) {
    S.snoreT -= pdt
    if (S.snoreT <= 0) { S.snoreT = 1.4; wd.__play_sound = { frequency: 82, duration: 0.5, volume: 0.22, type: 'sine' } }
  }
  S.blinkT = Math.max(0, S.blinkT - pdt)
  const lidNow = S.blinkT > 0 ? Math.min(1, tLid + Math.sin((0.7 - S.blinkT) / 0.7 * Math.PI) * 0.9) : tLid
  S.lid += (lidNow - S.lid) * Math.min(1, pdt * 8)
  S.smile += (tSmile - S.smile) * Math.min(1, pdt * 3)
  S.pulse = Math.max(0, S.pulse - pdt * 0.9)
  S.blush = Math.max(0.2, S.blush - pdt * 0.08)
  S.glow = Math.max(0, S.glow - pdt * 0.8)

  // ── the gnats: pests that swarm and poke the moon ──
  const NB = 6
  if (!S.bugs || S.bugs.length !== NB) {
    S.bugs = []
    for (let i = 0; i < NB; i++) {
      S.bugs.push({
        a: (i / NB) * Math.PI * 2,      // orbit angle around the moon
        av: 1.1 + (i % 3) * 0.5,        // angular speed
        r: 0.12 + (i % 2) * 0.05,       // orbit radius (uv units)
        rp: i * 1.7,                    // radius-wobble phase
        diveT: 1.5 + i * 0.6,           // countdown to next dive-bomb
        dive: 0,                        // 0..1 dive amount
      })
    }
    S.annoy = 0; S.shx = 0; S.shy = 0; S.swat = 0; S.buzzT = 0
  }
  if (typeof S.annoy !== 'number') S.annoy = 0
  if (typeof S.swat !== 'number') S.swat = 0
  if (typeof S.buzzT !== 'number') S.buzzT = 0

  let nearest = 999, diving = 0
  const bugU = []
  for (let i = 0; i < NB; i++) {
    const b = S.bugs[i]
    b.a += pdt * b.av * (b.dive > 0.3 ? 1.8 : 1.0)   // buzz faster mid-dive
    b.diveT -= pdt
    if (b.diveT <= 0 && b.dive <= 0.01) { b.dive = 1; b.diveT = 2.2 + (i % 4) * 0.8 }
    b.dive = Math.max(0, b.dive - pdt * 1.6)
    // radius: orbit ring, yanked inward to the moon's surface on a dive
    const ring = b.r + Math.sin(S.ma * 3.0 + b.rp) * 0.02
    const rad = ring * (1 - b.dive) + (mR + 0.006) * b.dive
    // buzzy jitter — they never look calm
    const jx = Math.sin(S.ma * 40 + i * 5.0) * 0.006
    const jy = Math.cos(S.ma * 33 + i * 7.0) * 0.006
    const bx = mcx + Math.cos(b.a) * rad + jx
    const by = mcy + Math.sin(b.a) * rad * 0.9 + jy
    const distSurf = Math.hypot(bx - mcx, by - mcy) - mR   // gap to the moon's skin
    const hot = Math.max(0, Math.min(1, 1 - distSurf / 0.05))
    nearest = Math.min(nearest, distSurf)
    diving = Math.max(diving, b.dive)
    bugU.push(bx, by, b.a * 6.0, hot)                       // wing phase = a*6 (fast flap)
  }

  // ── the moon's mood: pestered, then it swats ──
  const pestered = Math.min(1, Math.max(0, (0.05 - nearest) / 0.05) * 0.8 + diving * 0.6)
  S.annoy += (pestered - S.annoy) * Math.min(1, pdt * 4)
  const shk = S.annoy * 0.01
  S.shx = Math.sin(S.ma * 55) * shk
  S.shy = Math.cos(S.ma * 61) * shk
  // swat: a gnat actually lands → ring + shove the swarm out + an irritated tsk
  if (nearest < 0.004 && S.swat < 0.2) {
    S.swat = 1
    for (const b of S.bugs) { b.dive = 0; b.diveT = Math.max(b.diveT, 0.6 + Math.random() * 0.8); b.r = 0.12 + Math.random() * 0.08 }
    wd.__play_sound = [
      { frequency: 520, duration: 0.05, volume: 0.16, type: 'square' },
      { frequency: 300, duration: 0.08, volume: 0.12, type: 'triangle' },
    ]
  }
  S.swat = Math.max(0, S.swat - pdt * 2.2)

  // a faint continuous buzz while the swarm is close — mildly irritating, on purpose
  S.buzzT -= pdt
  if (S.annoy > 0.25 && S.buzzT <= 0) {
    S.buzzT = 0.22
    wd.__play_sound = { frequency: 1400 + S.annoy * 500, duration: 0.05, volume: 0.03 * S.annoy, type: 'sawtooth' }
  }

  // ── publish the whiteboard ──
  const U = [S.gx, S.gy, S.lid, S.smile, S.pulse, S.blush, S.sleep, S.glow,
             S.ma, S.annoy, S.shx, S.shy, S.swat, 0, 0, 0]
  for (let i = 0; i < NB; i++) {
    const o = 16 + i * 4
    U[o] = bugU[i * 4]; U[o + 1] = bugU[i * 4 + 1]; U[o + 2] = bugU[i * 4 + 2]; U[o + 3] = bugU[i * 4 + 3]
  }
  wd.gpuUniforms = U
} catch (e) { /* it would never admit to an error */ }

